import { useState } from "react";
import GlowAndShine from "./pages/GlowAndShine";
import ServicesPage from "./pages/ServicesPage";
import LoginPage from "./pages/LoginPage";
import SignUpPage from "./pages/SignUpPage";

export default function App() {
  const [page, setPage] = useState("home");

  if (page === "login")    return <LoginPage    onNavigate={setPage} />;
  if (page === "signup")   return <SignUpPage   onNavigate={setPage} />;
  if (page === "services") return <ServicesPage onNavigate={setPage} />;

  return <GlowAndShine onExplore={() => setPage("services")} onLogin={() => setPage("login")} onSignup={() => setPage("signup")} />;
}
